{
  "manifest_version": "0.4",
  "name": "yandex-tracker-mcp",
  "display_name": "Yandex Tracker MCP",
  "version": "0.7.1",
  "description": "Yandex Tracker MCP Server",
  "author": {
    "name": "KTS",
    "email": "hello@kts.tech",
    "url": "https://kts.tech"
  },
  "icon": "images/tracker-logo.png",
  "server": {
    "type": "uv",
    "entry_point": "yandex-tracker-mcp",
    "mcp_config": {
      "command": "uv",
      "args": [
        "run",
        "yandex-tracker-mcp"
      ],
      "env": {
        "PYTHONPATH": "${__dirname}",
        "TRACKER_TOKEN": "${user_config.tracker_token}",
        "TRACKER_IAM_TOKEN": "${user_config.tracker_iam_token}",
        "TRACKER_CLOUD_ORG_ID": "${user_config.tracker_cloud_org_id}",
        "TRACKER_ORG_ID": "${user_config.tracker_org_id}"
      }
    }
  },
  "compatibility": {
    "platforms": ["darwin", "linux", "win32"],
    "runtimes": {
      "python": ">=3.11"
    }
  },
  "tools": [
    {
      "name": "queues_get_all",
      "description": "List all available Yandex Tracker queues"
    },
    {
      "name": "queue_get_tags",
      "description": "Get all tags for a specific queue"
    },
    {
      "name": "queue_get_versions",
      "description": "Get all versions for a specific queue"
    },
    {
      "name": "queue_create_version",
      "description": "Create a new version in a specific queue"
    },
    {
      "name": "queue_get_fields",
      "description": "Get fields for a specific queue"
    },
    {
      "name": "queue_get_metadata",
      "description": "Get detailed metadata about a specific queue"
    },
    {
      "name": "users_get_all",
      "description": "Get information about user accounts registered in the organization"
    },
    {
      "name": "user_get",
      "description": "Get information about a specific user by login or UID"
    },
    {
      "name": "user_get_current",
      "description": "Get information about the current authenticated user"
    },
    {
      "name": "users_search",
      "description": "Search user based on login, email or real name (first or last name, or both)"
    },
    {
      "name": "get_global_fields",
      "description": "Get all global fields available in Yandex Tracker"
    },
    {
      "name": "get_statuses",
      "description": "Get all available issue statuses"
    },
    {
      "name": "get_issue_types",
      "description": "Get all available issue types"
    },
    {
      "name": "get_priorities",
      "description": "Get all available issue priorities"
    },
    {
      "name": "get_resolutions",
      "description": "Get all available issue resolutions"
    },
    {
      "name": "issue_get",
      "description": "Retrieve detailed issue information by ID"
    },
    {
      "name": "issue_get_url",
      "description": "Generate web URL for an issue"
    },
    {
      "name": "issue_get_comments",
      "description": "Fetch all comments for an issue"
    },
    {
      "name": "issue_add_comment",
      "description": "Add a comment to a Yandex Tracker issue"
    },
    {
      "name": "issue_update_comment",
      "description": "Update an existing comment in a Yandex Tracker issue"
    },
    {
      "name": "issue_delete_comment",
      "description": "Delete a comment from a Yandex Tracker issue"
    },
    {
      "name": "issue_add_link",
      "description": "Create a link between a Yandex Tracker issue and another issue"
    },
    {
      "name": "issue_delete_link",
      "description": "Delete a link between a Yandex Tracker issue and another issue"
    },
    {
      "name": "issue_get_links",
      "description": "Get related issue links"
    },
    {
      "name": "issue_get_worklogs",
      "description": "Retrieve worklog entries"
    },
    {
      "name": "issue_add_worklog",
      "description": "Add a worklog entry (log spent time) to an issue"
    },
    {
      "name": "issue_update_worklog",
      "description": "Update a worklog entry (spent time record) in an issue"
    },
    {
      "name": "issue_delete_worklog",
      "description": "Delete a worklog entry (spent time record) from an issue"
    },
    {
      "name": "issue_get_attachments",
      "description": "Get attachments for an issue"
    },
    {
      "name": "issue_get_checklist",
      "description": "Get checklist items of a Yandex Tracker issue by its id"
    },
    {
      "name": "issue_get_transitions",
      "description": "Get possible status transitions for a Yandex Tracker issue"
    },
    {
      "name": "issue_get_changelog",
      "description": "Get the change history (changelog) of a Yandex Tracker issue: status transitions, field edits, comment changes and executed triggers, who changed what and when. Supports cursor pagination and field/type filters."
    },
    {
      "name": "issue_execute_transition",
      "description": "Execute a status transition for a Yandex Tracker issue. Must call issue_get_transitions first to get available transition IDs."
    },
    {
      "name": "issue_close",
      "description": "Close a Yandex Tracker issue with a resolution. Automatically finds a transition to done status. Must call get_resolutions first."
    },
    {
      "name": "issue_create",
      "description": "Create a new issue in a Yandex Tracker queue"
    },
    {
      "name": "issue_update",
      "description": "Update an existing Yandex Tracker issue"
    },
    {
      "name": "issue_move",
      "description": "Move a Yandex Tracker issue to a different queue"
    },
    {
      "name": "issues_find",
      "description": "Search issues using Yandex Tracker Query Language"
    },
    {
      "name": "issues_count",
      "description": "Count issues matching a query using Yandex Tracker Query Language"
    }
  ],
  "user_config": {
    "tracker_token": {
      "type": "string",
      "title": "Yandex Tracker Token",
      "description": "OAuth token for accessing Yandex Tracker API",
      "required": false,
      "sensitive": true,
      "default": ""
    },
    "tracker_iam_token": {
      "type": "string",
      "title": "Yandex IAM Token",
      "description": "IAM token for service-to-service authentication",
      "required": false,
      "sensitive": true,
      "default": ""
    },
    "tracker_cloud_org_id": {
      "type": "string",
      "title": "Tracker Cloud Org Id",
      "description": "ID of Yandex Cloud Organization",
      "required": false,
      "sensitive": false,
      "default": ""
    },
    "tracker_org_id": {
      "type": "string",
      "title": "Tracker Org Id",
      "description": "ID of Yandex 360 Organization",
      "required": false,
      "sensitive": false,
      "default": ""
    }
  },
  "keywords": [
    "yandex",
    "yandex-tracker"
  ],
  "license": "Apache 2.0",
  "repository": {
    "type": "git",
    "url": "https://github.com/aikts/yandex-tracker-mcp"
  }
}

